// ============================================
// PLANT HEADER - Helpers
// ============================================

context.handlebars.registerHelper('statusClass', (status) => {
  if (!status) return 'other';
  const s = status.toString().toLowerCase();
  if (s === 'generating') return 'generating';
  if (s === 'critical') return 'critical';
  if (s === 'no_communication') return 'no_communication';
  return 'other';
});

context.handlebars.registerHelper('statusLabel', (status) => {
  if (!status) return 'UNKNOWN';
  const s = status.toString().toLowerCase();
  if (s === 'generating') return 'GENERATING';
  if (s === 'critical') return 'CRITICAL';
  if (s === 'no_communication') return 'NO COMM';
  return status.toUpperCase();
});

context.handlebars.registerHelper('pctColor', (value, highThreshold, midThreshold) => {
  if (value === null || value === undefined) return 'gray';
  if (value >= highThreshold) return 'green';
  if (value >= midThreshold) return 'yellow';
  return 'red';
});

context.handlebars.registerHelper('rainColor', (signal) => {
  if (signal === 0) return 'green';
  if (signal === 1) return 'blue';
  return 'gray';
});

context.handlebars.registerHelper('rainLabel', (signal) => {
  if (signal === 0) return 'DRY';
  if (signal === 1) return 'RAIN';
  return '—';
});

