// Drill-down para strings
context.element.querySelectorAll('.inverter-box').forEach(function(box) {
  if (box.dataset.listenerAdded) return;
  box.dataset.listenerAdded = 'true';

  box.addEventListener('click', function(e) {
    e.preventDefault();
    var deviceId = box.dataset.deviceId;
    var deviceName = box.dataset.deviceName;
    var cabin = box.dataset.cabin;
    var card = box.closest('.cabine-card');

    // Esconde view de inversores
    card.querySelector('.inverters-view').style.display = 'none';

    // Mostra view de strings
    var stringsView = card.querySelector('.strings-view');
    stringsView.style.display = 'flex';

    // Filtra strings do inversor clicado
    stringsView.querySelectorAll('.string-box').forEach(function(s) {
      s.style.display = s.dataset.deviceId === deviceId ? 'block' : 'none';
    });

    // Atualiza título
    card.querySelector('.title-text').textContent = deviceName;

    // Mostra botão voltar
    card.querySelector('.back-btn').style.display = 'inline';
  });
});

// Botão voltar
context.element.querySelectorAll('.back-btn').forEach(function(btn) {
  if (btn.dataset.listenerAdded) return;
  btn.dataset.listenerAdded = 'true';

  btn.addEventListener('click', function(e) {
    e.preventDefault();
    var cabin = btn.dataset.cabin;
    var card = btn.closest('.cabine-card');

    // Mostra view de inversores
    card.querySelector('.inverters-view').style.display = 'flex';

    // Esconde view de strings
    card.querySelector('.strings-view').style.display = 'none';

    // Restaura título
    card.querySelector('.title-text').textContent = 'Cabin ' + cabin;

    // Esconde botão voltar
    btn.style.display = 'none';
  });
});

options.helpers:
// Group by cabin
context.handlebars.registerHelper('groupByCabin', function(array) {
  const grouped = {};
  array.forEach(item => {
    const key = item.cabin;
    if (!grouped[key]) grouped[key] = [];
    grouped[key].push(item);
  });
  return Object.entries(grouped).map(([k, v]) => ({ key: k, items: v }));
});

// Filter by device type
context.handlebars.registerHelper('filterByType', function(items, type) {
  return items.filter(item => item.device_type === type);
});

// Check if inverter is OK (state_simplified === 2)
context.handlebars.registerHelper('isInverterOk', function(state) {
  return state === 2;
});

// Check if relay is OK (breaker_position >= 1)
context.handlebars.registerHelper('isRelayOk', function(state) {
  return state >= 1;
});

// Check if string is OK (current >= 1)
context.handlebars.registerHelper('isStringOk', function(current) {
  return current >= 1;
});

// Get total power from inverters
context.handlebars.registerHelper('totalPower', function(items) {
  const inverter = items.find(i => i.device_type === 'inverter' && i.total_power);
  return inverter ? inverter.total_power : 0;
});

// Check if has relay or logger
context.handlebars.registerHelper('hasSidebarDevices', function(items) {
  return items.some(i => i.device_type === 'relay' || i.device_type === 'logger');
});

context.handlebars.registerHelper('eq', (a, b) => a == b);
context.handlebars.registerHelper('neq', (a, b) => a != b);

