const API_KEY = '35430ed0e569a39bcd737092723631bc';

setTimeout(() => {
  const mapEl = document.getElementById('leaflet');
  
  if (!mapEl) {
    console.error('Leaflet element not found');
    return;
  }
  
  // Parse plant data
  let plants = [];
  try {
    const plantsData = mapEl.getAttribute('data-plants');
    plants = JSON.parse(plantsData);
    if (!Array.isArray(plants)) plants = [];
  } catch (e) {
    console.error('Error parsing plant data:', e);
    mapEl.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#999;font-size:14px;">⚠️ Error loading data</div>';
    return;
  }
  
  // Filter plants with valid coordinates
  plants = plants.filter(p => {
    const lat = parseFloat(p.latitude);
    const lon = parseFloat(p.longitude);
    return !isNaN(lat) && !isNaN(lon);
  });
  
  if (plants.length === 0) {
    mapEl.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#999;font-size:14px;">⚠️ No plants with available coordinates</div>';
    return;
  }
  
  console.log('Plants loaded:', plants);
  
  // Function to get visual configuration based on status
  function getStatusConfig(status) {
    const configs = {
      'critical': { color: '#DC2626', icon: '⚠️', label: 'Critical' },
      'acknowledged': { color: '#F97316', icon: '✓', label: 'Acknowledged' },
      'generating': { color: '#10B981', icon: '☀️', label: 'Generating' },
      'no_communication': { color: '#6B7280', icon: '✕', label: 'No Communication' },
      'unknown': { color: '#9CA3AF', icon: '?', label: 'Unknown' }
    };
    return configs[status] || configs['unknown'];
  }
  
  import("https://esm.sh/leaflet@1.9.4").then(({ default: L }) => {
    
    // Remover mapa anterior se existir (SEM salvar estado)
    if (window.leafletMap) {
      window.leafletMap.remove();
    }
    
    // Calculate center and bounds for all plants
    const bounds = L.latLngBounds(plants.map(p => [parseFloat(p.latitude), parseFloat(p.longitude)]));
    
    const map = L.map('leaflet', {
      zoomControl: true
    });
    
    window.leafletMap = map;
    
    // Satellite
    L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
      attribution: 'Esri',
      maxZoom: 18
    }).addTo(map);
    
    // Clouds
    let clouds = L.tileLayer('https://tile.openweathermap.org/map/clouds_new/{z}/{x}/{y}.png?appid=' + API_KEY, {
      opacity: 0.85,
      maxZoom: 18
    }).addTo(map);
    
    let cloudsVisible = true;
    
    // Cloud button control
    const toggleBtn = document.getElementById('cloudToggle');
    if (toggleBtn) {
      toggleBtn.addEventListener('click', () => {
        if (cloudsVisible) {
          map.removeLayer(clouds);
          toggleBtn.classList.remove('active');
          toggleBtn.textContent = '☁️ Clouds (OFF)';
        } else {
          clouds.addTo(map);
          toggleBtn.classList.add('active');
          toggleBtn.textContent = '☁️ Clouds';
        }
        cloudsVisible = !cloudsVisible;
      });
    }
    
    // Adicionar marcador para cada usina
    plants.forEach((plant, index) => {
      const lat = parseFloat(plant.latitude);
      const lon = parseFloat(plant.longitude);
      const name = plant.power_plant_name;
      const location = plant.location;
      const capacity = plant.capacity;
      const status = plant.status || 'unknown';
      const activePower = parseFloat(plant.active_power_kw) || 0;
      const highAlarmsCount = parseInt(plant.high_alarms_count) || 0;
      
      // Obter configuração de cor e ícone baseado no status
      const statusConfig = getStatusConfig(status);
      
      const icon = L.divIcon({
        className: '',
        html: '<div style="background:' + statusConfig.color + ';width:36px;height:36px;border-radius:50%;border:3px solid #fff;box-shadow:0 3px 10px rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;font-size:20px;">' + statusConfig.icon + '</div>',
        iconSize: [36, 36],
        iconAnchor: [18, 18]
      });
      
      // Criar conteúdo do popup
      let popupContent = '<div style="min-width:200px;">' +
        '<b style="font-size:14px;">' + name + '</b><br>' +
        '<span style="color:#666;font-size:12px;">' + location + '</span><br>' +
        '<span style="font-size:12px;"><b>Capacity:</b> ' + capacity + ' kWp</span><br>' +
        '<span style="font-size:12px;"><b>Active Power:</b> ' + activePower.toFixed(2) + ' kW</span><br>';
      
      // Adicionar alarmes HIGH se houver
      if (highAlarmsCount > 0) {
        popupContent += '<span style="font-size:12px;color:#DC2626;"><b>⚠️ HIGH Alarms:</b> ' + highAlarmsCount + '</span><br>';
      }
      
      popupContent += '<span style="display:inline-block;margin-top:4px;padding:2px 8px;background:' + statusConfig.color + ';color:white;border-radius:4px;font-size:11px;font-weight:bold;">' + statusConfig.label + '</span>' +
        '</div>';
      
      const marker = L.marker([lat, lon], {icon: icon})
        .addTo(map)
        .bindPopup(popupContent);
      
      // Abrir popup no hover
      marker.on('mouseover', function() {
        this.openPopup();
      });
      
      // Fechar popup quando sair do hover
      marker.on('mouseout', function() {
        this.closePopup();
      });
      
      // Redirecionar ao clicar
      marker.on('click', function() {
        const url = 'https://nexus-gridco.com.br/d/ad4v9dd/powerplant-view?orgId=1&from=now%2Fd&to=now&timezone=browser&var-power_plant_id=' + plant.id + '&refresh=30s';
        window.location.href = url;
      });
      
      // Se for apenas uma usina, abrir o popup
      if (plants.length === 1) {
        marker.openPopup();
      }
    });
    
    // SEMPRE recentralizar (a cada refresh)
    if (plants.length === 1) {
      map.setView([parseFloat(plants[0].latitude), parseFloat(plants[0].longitude)], 16);
    } else {
      map.fitBounds(bounds, { padding: [50, 50] });
    }
    
    setTimeout(() => map.invalidateSize(), 200);
    
    function updateTime() {
      const el = document.getElementById('time');
      if (el) {
        el.textContent = 'Update: ' + new Date().toLocaleString('pt-BR', {
          day:'2-digit',
          month:'2-digit',
          hour:'2-digit',
          minute:'2-digit'
        });
      }
    }
    updateTime();
    
    // Atualizar nuvens a cada 30 min
    setInterval(() => {
      if (cloudsVisible) {
        try {
          map.removeLayer(clouds);
          clouds = L.tileLayer('https://tile.openweathermap.org/map/clouds_new/{z}/{x}/{y}.png?appid=' + API_KEY + '&_=' + Date.now(), {
            opacity: 0.85,
            maxZoom: 18
          }).addTo(map);
          updateTime();
        } catch(e) {
          console.error('Error updating clouds:', e);
        }
      }
    }, 1800000);
    
  }).catch(error => {
    console.error('Error loading Leaflet:', error);
    mapEl.innerHTML = '<div style="padding:20px;color:red;text-align:center;">Error loading map: ' + error.message + '</div>';
  });
  
}, 100);

var apiEndpoint = context.grafana.replaceVariables('${api_endpoint}');

// Atualizar contador de alarmes pendentes
var pendingRows = context.element.querySelectorAll('#alarm-table .alarms__row:not(.alarms__row--ack)');
var countEl = context.element.querySelector('#pending-count');
var btnEl = context.element.querySelector('#acknowledge-all-btn');

if (countEl && pendingRows.length > 0) {
  countEl.textContent = '(' + pendingRows.length + ' pending)';
}

if (btnEl) {
  if (btnEl.dataset.listenerAdded) return;
  btnEl.dataset.listenerAdded = 'true';

  if (pendingRows.length === 0) {
    btnEl.disabled = true;
    btnEl.textContent = 'No Pending Alarms';
  }

  btnEl.addEventListener('click', function () {
    var pendingIds = [];
    var rows = context.element.querySelectorAll('#alarm-table .alarms__row:not(.alarms__row--ack)');
    rows.forEach(function (row) {
      var alarmId = row.getAttribute('data-id');
      if (alarmId) {
        pendingIds.push(alarmId);
      }
    });

    if (pendingIds.length === 0) {
      alert('No pending alarms to acknowledge.');
      return;
    }

    if (!confirm('Are you sure you want to acknowledge all ' + pendingIds.length + ' pending alarms?')) {
      return;
    }

    var userName = window.grafanaBootData && window.grafanaBootData.user ? window.grafanaBootData.user.name : 'Unknown';

    var url = apiEndpoint + '/events-alarms/acknowledge/multiple';
    var payload = {
      acknowledged_by: userName,
      ids: pendingIds
    };

    btnEl.disabled = true;
    btnEl.textContent = 'Processing...';

    fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    })
      .then(function (response) {
        if (response.ok) {
          alert('All alarms acknowledged successfully!');
          location.reload();
        } else {
          alert('Failed to acknowledge alarms. Status: ' + response.status);
          btnEl.disabled = false;
          btnEl.textContent = 'Acknowledge All';
        }
      })
      .catch(function (error) {
        alert('Error: ' + error.message);
        btnEl.disabled = false;
        btnEl.textContent = 'Acknowledge All';
      });
  });
}

// Event listeners para botões individuais
context.element.querySelectorAll('.acknowledge-btn').forEach(function (btn) {
  if (btn.dataset.listenerAdded) return;
  btn.dataset.listenerAdded = 'true';

  btn.addEventListener('click', function (event) {
    event.stopPropagation();
    var row = btn.closest('tr');
    var alarmId = row.getAttribute('data-id');

    if (!confirm('Are you sure you want to acknowledge this alarm?')) {
      return;
    }

    var userName = window.grafanaBootData && window.grafanaBootData.user ? window.grafanaBootData.user.name : 'Unknown';
    var url = apiEndpoint + '/events-alarms/' + alarmId + '/acknowledge';
    var payload = { acknowledged_by: userName };

    fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    })
      .then(function (response) {
        if (response.ok) {
          alert('Alarm acknowledged successfully!');
          location.reload();
        } else {
          alert('Failed to acknowledge alarm. Status: ' + response.status);
        }
      })
      .catch(function (error) {
        alert('Error: ' + error.message);
      });
  });
});

